    #[derive(Clone, Copy, Debug, PartialEq, Eq)]
    pub enum DeliveryGuarantee {
        /// Fire and forget
        AtMostOnce,
        /// Retry until acknowledged
        AtLeastOnce,
        /// Deduplicated delivery
        ExactlyOnce,
    }

    #[derive(Clone, Copy, Debug, PartialEq, Eq)]
