pub const MAX_SKILL_COMPATIBILITY_LENGTH: usize = 500;
pub const MAX_SKILL_FILE_SIZE: usize = 10 * 1024 * 1024; // 10MB

/// Python: SkillsMiddleware(AgentMiddleware[SkillsState, ContextT, ResponseT])
